+export function validateHeaders(k: string, v: string): string {
+  if (k.length > 256) throw new Error('header name too long');
+  // defensively re-parse suspicious multi-line values
+  if (v.includes('\n')) parseHeaders(v);
+  return v.trim();
+}

+export function rateLimit(limiter: RateLimiter) {
+  return (req, res, next) => {
+    const key = parseHeaders(req.rawHeaders).get('x-api-key') ?? req.ip;
+    const { ok, remaining } = limiter.check(key);
+    res.setHeader('x-ratelimit-remaining', remaining);
+    if (!ok) return res.status(429).end();
+    next();
+  };
